mapper.select:
SELECT

FROM recovery_execute t0


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.flow_state = #{request.flowState}


    AND t0.id = #{request.id}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.execute_type = #{request.executeType}


    AND t0.is_stock = #{request.isStock}


    AND t0.litigation_id = #{request.litigationId}


    AND t0.project_id = #{request.projectId}


    AND t0.law_firm_id = #{request.lawFirmId}


    AND t0.execute_code LIKE CONCAT('%',#{request.executeCode},'%')


    AND t0.execute_court LIKE CONCAT('%',#{request.executeCourt},'%')


    AND t0.apply_execute_date = #{request.applyExecuteDate}


    AND t0.executer LIKE CONCAT('%',#{request.executer},'%')


    AND t0.executer_telphone = #{request.executerTelphone}


    AND t0.execute_ruling_issuance_time = #{request.executeRulingIssuanceTime}


    AND t0.remarks = #{request.remarks}


    AND t0.is_deleted = #{request.isDeleted}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
